import React, { useState } from 'react';
import Header from '../components/header/header';
import Footer from '../components/footer/footer';
import { FaTimes, FaSearchPlus, FaChevronLeft, FaChevronRight } from 'react-icons/fa';
import '../components/gallery/gallery.css';
import '../styles/service-page.css';

// Generate 72 images using the requested pattern: img1.jpg to img72.jpg
const allProjects = Array.from({ length: 61 }, (_, i) => ({
  id: i + 1,
  src: `https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img${i + 1}.jpg`,
  title: `Premium Fencing Masterpiece #${i + 1}`
}));

const ProjectsPage: React.FC = () => {
  const [lightboxOpen, setLightboxOpen] = useState(false);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);

  const openLightbox = (index: number) => {
    setCurrentImageIndex(index);
    setLightboxOpen(true);
    document.body.style.overflow = 'hidden';
  };

  const closeLightbox = () => {
    setLightboxOpen(false);
    document.body.style.overflow = 'unset';
  };

  const nextImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentImageIndex((prev) => (prev + 1) % allProjects.length);
  };

  const prevImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentImageIndex((prev) => (prev - 1 + allProjects.length) % allProjects.length);
  };

  return (
    <div className="projects-page">
      <Header />
      
      <section className="service-hero hero-short">
        <div className="hero-img-container">
          <img src="https://ik.imagekit.io/dloitl7fd8/gellery-for-jsk/images/img51.jpg" alt="Fencing Portfolio" className="hero-img" />
          <div className="hero-overlay"></div>
        </div>
        <div className="container">
          <div className="service-hero-content" style={{ textAlign: 'center', maxWidth: '850px', margin: '0 auto' }}>
            <span className="badge">Complete Portfolio</span>
            <h1 className="hero-title" style={{ fontSize: '3.5rem', marginBottom: '1rem' }}>Our Full <span className="highlight">Project Gallery</span></h1>
            <p className="hero-subtitle" style={{ margin: '0 auto', fontSize: '1.2rem', opacity: '0.8' }}>
              Browse our complete legacy of over 60+ high-end fencing installations across the region. Excellence in every square foot.
            </p>
          </div>
        </div>
      </section>

      <section className="gallery-section" style={{ backgroundColor: 'white' }}>
        <div className="container">
          <div className="masonry-grid">
            {allProjects.map((image, index) => (
              <div 
                key={image.id} 
                className="masonry-item" 
                onClick={() => openLightbox(index)}
              >
                <div className="gallery-card">
                  <div className="gallery-img-wrapper">
                    <img 
                      src={image.src} 
                      alt={image.title} 
                      className="gallery-img" 
                      loading="lazy" 
                    />
                    <div className="gallery-overlay">
                      <FaSearchPlus className="zoom-icon" />
                      <div className="overlay-info">
                        <h3>{image.title}</h3>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Lightbox Overlay */}
      {lightboxOpen && (
        <div className="lightbox-overlay" onClick={closeLightbox}>
          <div className="lightbox-close" onClick={closeLightbox}>
            <FaTimes />
          </div>

          <div className="lightbox-nav-btn prev" onClick={prevImage}>
            <FaChevronLeft />
          </div>
          
          <div className="lightbox-content" onClick={(e) => e.stopPropagation()}>
            <img 
              src={allProjects[currentImageIndex].src} 
              alt={allProjects[currentImageIndex].title} 
              className="lightbox-main-img"
            />
            <div className="lightbox-caption">
              <h4>{allProjects[currentImageIndex].title}</h4>
            </div>
          </div>

          <div className="lightbox-nav-btn next" onClick={nextImage}>
            <FaChevronRight />
          </div>
        </div>
      )}

      <Footer />
    </div>
  );
};

export default ProjectsPage;
